// src/services/UserService.js
import UserRepository from '../repositories/UserRepository';
import { supabase } from '../utils/supabaseClient';

const UserService = {
  async getAllUsers() {
    return await UserRepository.getAll();
  },

  async getUserById(id) {
    return await UserRepository.getById(id);
  },

  async createUser(userData) {
    const { email, password, name, role } = userData;

    // Create auth user via Supabase Admin (or regular signup)
    const { data: authData, error } = await supabase.auth.signUp({ email, password });
    if (error) throw error;

    // Create profile
    const profile = await UserRepository.create({
      id: authData.user.id,
      email,
      name,
      role: role || 'standard',
      created_at: new Date().toISOString()
    });

    return profile;
  },

  async updateUser(id, userData) {
    const allowedFields = ['name', 'role', 'email'];
    const filtered = Object.fromEntries(
      Object.entries(userData).filter(([k]) => allowedFields.includes(k))
    );
    return await UserRepository.update(id, filtered);
  },

  async deleteUser(id) {
    // Delete profile (auth user deletion requires admin API)
    return await UserRepository.remove(id);
  },

  async getUserProfile(userId) {
    return await UserRepository.getById(userId);
  }
};

export default UserService;
